import * as React from 'react';
import { styled } from '@mui/material/styles';
import Switch from '@mui/material/Switch';
import FormControlLabel from '@mui/material/FormControlLabel';

const CustomSwitch = styled(Switch)(({ theme }) => ({
  width: 60,   // Adjusted width
  height: 34,  // Adjusted height
  padding: 0,
  display: 'flex',
  alignItems: 'center',
  '& .MuiSwitch-switchBase': {
    padding: 3,  // Small padding around the thumb
    '&.Mui-checked': {
      transform: 'translateX(26px)', // Ensures thumb stays inside the track
      '& + .MuiSwitch-track': {
        backgroundColor: '#e0e0e0', // Checked background
      },
      '& .MuiSwitch-thumb': {
        backgroundColor: '#cacaca', // Thumb color when checked
      },
    },
  },
  '& .MuiSwitch-thumb': {
    width: 28,  // Reduced thumb size
    height: 28, // Reduced thumb size
    backgroundColor: '#666666', // Thumb color when unchecked
    boxShadow: 'none',  // Remove default shadow
  },
  '& .MuiSwitch-track': {
    borderRadius: 34 / 2, // Radius matches the thumb's height to make it rounded
    backgroundColor: '#1A1A1A', // Track color when unchecked
    opacity: 1,
    boxSizing: 'border-box',  // Ensures border does not affect sizing
  },
}));

export default function Toggle() {
  const [checked, setChecked] = React.useState(false);

  const handleChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    setChecked(event.target.checked);
  };

  return (
    <FormControlLabel className='flex gap-2'
      control={
        <CustomSwitch
          checked={checked}
          onChange={handleChange}
        />
      }
      label={checked ? 'Dark mode' : 'Light mode'}
    />
  );
}
